    function stcPosTour(targetEl){
        const sl=document.getElementById('stc-tour-spotlight'),card=document.getElementById('stc-tour-card'),panel=document.getElementById('stc-panel');
        if(!targetEl||!panel)return;
        sl.classList.remove('visible');card.classList.remove('visible');
        const pr=panel.getBoundingClientRect(),r=targetEl.getBoundingClientRect(),pad=8,cw=270,ch=230;
        sl.style.left=Math.max(r.left-pad,pr.left)+'px';sl.style.top=Math.max(r.top-pad,pr.top)+'px';
        sl.style.width=Math.max(Math.min(r.right+pad,pr.right)-Math.max(r.left-pad,pr.left),0)+'px';
        sl.style.height=Math.max(Math.min(r.bottom+pad,pr.bottom)-Math.max(r.top-pad,pr.top),0)+'px';
        card.classList.remove('arrow-up','arrow-down','arrow-right');
        let cx,cy;
        if(pr.bottom-r.bottom>=ch+18){cy=r.bottom+14;cx=r.left;card.classList.add('arrow-up');}
        else if(r.top-pr.top>=ch+18){cy=r.top-ch-14;cx=r.left;card.classList.add('arrow-down');}
        else if(pr.right-r.right>=cw+18){cx=r.right+14;cy=r.top;card.classList.add('arrow-right');}
        else{cx=pr.right-cw-14;cy=pr.bottom-ch-14;}
        cx=Math.min(Math.max(cx,pr.left+8),pr.right-cw-8);
        cy=Math.min(Math.max(cy,pr.top+8),pr.bottom-ch-8);
        card.style.left=cx+'px';card.style.top=cy+'px';
        sl.classList.add('visible');card.classList.add('visible');
    }

