const GR_LOGO_B64 = '';
let GR_GEMINI_KEY = GM_getValue('geminiKey', '');

// ── Utility helpers ───────────────────────────────────────────────────────────
function grB64ToUint8(b64) {
    const _atob = (typeof atob === 'function') ? atob
                : (typeof unsafeWindow !== 'undefined' && unsafeWindow.atob) ? unsafeWindow.atob.bind(unsafeWindow)
                : s => window.atob(s);
    const bin = _atob(b64);
    const u8  = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
    return u8;
}

function grArrayBufToB64(buf) {
    const bytes = new Uint8Array(buf);
    let bin = '';
    for (let i = 0; i < bytes.length; i += 8192)
        bin += String.fromCharCode(...bytes.subarray(i, i + 8192));
    return btoa(bin);
}

function grLoadScript(src) {
    return new Promise((resolve, reject) => {
        if (document.querySelector('script[src="' + src + '"]')) { resolve(); return; }
        const s = document.createElement('script');
        s.src = src; s.onload = resolve;
        s.onerror = () => reject(new Error('Failed to load ' + src));
        document.head.appendChild(s);
    });
}

// ── Scrape session meta ───────────────────────────────────────────────────────
function grScrapePageMeta() {
    const data = { courseTitle:'', startDate:'', endDate:'', customer:'', location:'', instructor:'' };
    const h4Sels = [
        'app-session-heading h4', '.session-title-row h4',
        '.session-detail-header h4', 'app-classroom-session-details h4',
        '.session-title h4', '.course-title h4', 'h4.title', 'h4'
    ];
    const isSane = t => { const w = t.split(/\s+/).filter(w => /[a-zA-Z]{2,}/.test(w)); return t.length >= 5 && t.length <= 150 && w.length >= 2; };
    for (const sel of h4Sels) {
        for (const el of document.querySelectorAll(sel)) {
            const c = el.cloneNode(true);
            c.querySelectorAll('.badge,[class*="badge"],button,input,textarea,script,style').forEach(n => n.remove());
            const t = c.textContent.replace(/\s+/g, ' ').trim();
            if (isSane(t)) { data.courseTitle = t; break; }
        }
        if (data.courseTitle) break;
    }
    if (!data.courseTitle) {
        const pt = document.title.replace(/[|\-\u2013\u2014].*/, '').trim();
        if (isSane(pt) && !/home|dashboard|login|session/i.test(pt)) data.courseTitle = pt;
    }
    document.querySelectorAll('.detail-item').forEach(item => {
        const strong = item.querySelector('strong');
        if (!strong) return;
        // Aggressive normalization: NBSP → space, collapse whitespace, lowercase, strip ALL colons
        const lbl = strong.textContent.replace(/\u00a0/g,' ').replace(/\s+/g,' ').trim().toLowerCase().replace(/:/g,'').trim();
        const val = item.textContent.replace(strong.textContent, '').trim();
        // Match Date(s) ONLY — never "Withdrawal Date", "Expiration", "Signup End Date", etc.
        if (lbl === 'date(s)' || lbl === 'date' || lbl === 'class date(s)' || lbl === 'class date') {
            const parts = val.split(' - ');
            data.startDate = parts[0].trim();
            if (parts[1]) data.endDate = parts[1].trim();
        }
        // Prefer the short "Class:" detail-item value over the verbose Catalog/Calendar one.
        // Strip the (id open_in_new) reference link wrapper and any (Price Excludes...) disclaimer.
        if (lbl === 'class') {
            const clean = val
                .replace(/\(\d+\s*open_in_new\)/g, '')
                .replace(/open_in_new/g, '')
                .replace(/\(legacy[^)]*\)/gi, '')
                .replace(/\s*-?\s*\(Price Excludes[^)]*\)/i, '')
                .replace(/\s+/g, ' ')
                .trim();
            if (clean && clean.length >= 3 && clean.length <= 100) data.courseTitle = clean;
        }
        // NOTE: instructor scrape removed — user types it in manually.
    });
    // Facility section: customer = facility-name-link text; location = joined address lines
    const facilityLink = document.querySelector('.facility-name-link');
    if (facilityLink) {
        data.customer = facilityLink.textContent.replace(/\s+/g,' ').trim();
        const facilitySec = facilityLink.closest('.detail-section');
        if (facilitySec) {
            const lines = [];
            facilitySec.querySelectorAll('.detail-item').forEach(it => {
                if (it.querySelector('.facility-name-link')) return; // skip the name line itself
                if (it.querySelector('strong')) return;               // skip "Corporate Account:" and other labeled lines
                const t = it.textContent.replace(/\s+/g,' ').trim();
                if (t) lines.push(t);
            });
            data.location = lines.join(', ');
        }
    }
    return data;
}

// ── Scrape enrolled students ──────────────────────────────────────────────────
function grScrapeStudentsFromPage() {
    const result = [];
    // Primary: .student-name a + mailto link in same row (confirmed selectors)
    document.querySelectorAll('tr').forEach(row => {
        const nameEl  = row.querySelector('.student-name a');
        const mailEl  = row.querySelector('a[href^="mailto:"]');
        if (nameEl) {
            const name  = nameEl.textContent.trim();
            const email = mailEl ? mailEl.href.replace('mailto:', '').trim() : '';
            if (name && name.length > 1) result.push({ name, email });
        }
    });
    // Fallback: generic student-item rows
    if (!result.length) {
        document.querySelectorAll('.student-row, .enrolled-student, [class*="student-item"]').forEach(row => {
            const nameEl  = row.querySelector('.student-name, [class*="student-name"], td:first-child');
            const emailEl = row.querySelector('.student-email, [class*="email"], td:nth-child(3)');
            if (nameEl) {
                const name  = nameEl.textContent.trim();
                const email = emailEl ? emailEl.textContent.trim() : '';
                if (name && name.length > 1) result.push({ name, email });
            }
        });
    }
    return result;
}

// ── Parse pasted/uploaded text ────────────────────────────────────────────────
function grParseNamesText(text) {
    const lines = text.trim().split(/\r?\n/).filter(l => l.trim());
    return lines.map(line => {
        line = line.trim();
        const parts = line.split('\t');
        if (parts.length >= 2) {
            const a = parts[0].trim(), b = parts[1].trim();
            if (b.includes('@')) return { name: a, email: b };
            return { name: a + ' ' + b, email: parts[2] ? parts[2].trim() : '' };
        }
        const cols = line.split(',').map(s => s.trim());
        if (cols.length >= 2 && cols[1].includes('@')) return { name: cols[0], email: cols[1] };
        return { name: line, email: '' };
    }).filter(r => r.name);
}

// ── Gemini vision (image/PDF upload) ─────────────────────────────────────────
async function grCallGemini(base64data, mediaType) {
    const prompt = `This is a class roster (could be a Safety Unlimited typed roster, an AHA handwritten roster, or any tabular class list). Extract every student row.

Return ONLY a raw JSON array — no markdown fences, no commentary:
[{"name":"John Smith","email":"john@example.com"},{"name":"Jane Doe","email":""}]

Rules:
- Each numbered/listed row = ONE student
- "name" = the student's full name (first + last, plus middle if present)
- "email" = the student's email address if visible, else ""
- SKIP completely empty numbered rows
- SKIP column headers (lines like "Student Name", "Email Address", "Address", "#")
- SKIP the class info block at the top (Class:, Instructor:, Date:, Customer:, Location:, Hours:)
- SKIP footer text and page numbers
- Fix obvious OCR errors in emails (spaces, 0 vs O, l vs 1)
- Output VALID JSON only. Use commas between fields and between objects.`;
    const body = JSON.stringify({
        contents: [{ parts: [
            { inline_data: { mime_type: mediaType, data: base64data } },
            { text: prompt }
        ]}],
        generationConfig: { temperature: 0, maxOutputTokens: 8192 }
    });
    const models = ['gemini-2.5-flash', 'gemini-2.5-flash-lite', 'gemini-2.0-flash'];
    let lastErr = null;
    for (const model of models) {
        const url = 'https://generativelanguage.googleapis.com/v1beta/models/' + model + ':generateContent?key=' + GR_GEMINI_KEY;
        try {
            const text   = await emsGeminiPost(url, body);
            const data   = JSON.parse(text);
            const raw    = data?.candidates?.[0]?.content?.parts?.[0]?.text || '';
            console.log('[SUI] Gemini raw response from ' + model + ':', raw);
            const parsed = emsParseGeminiJSON(raw);
            if (!Array.isArray(parsed)) throw new Error('Unexpected response format');
            return parsed.filter(r => r && r.name).map(r => ({ name: (r.name||'').trim(), email: (r.email||'').trim() }));
        } catch(e) {
            if (e.message === 'QUOTA' || e.message === 'OVERLOAD') {
                lastErr = e.message === 'QUOTA'
                    ? 'Quota hit, trying next model...'
                    : 'Gemini overloaded, trying next model...';
                continue;
            }
            throw e;
        }
    }
    throw new Error(lastErr || 'All Gemini models failed.');
}

// ── File upload handler ───────────────────────────────────────────────────────
async function grHandleUpload(file, statusEl, onDone) {
    const ext = file.name.toLowerCase().split('.').pop();
    if (['csv','tsv','txt'].includes(ext)) {
        statusEl.textContent = 'Reading file…';
        const result = grParseNamesText(await file.text());
        if (!result.length) { statusEl.textContent = 'No names found.'; return; }
        statusEl.textContent = '✅ Found ' + result.length + ' students';
        onDone(result); return;
    }
    if (['xlsx','xls'].includes(ext)) {
        statusEl.textContent = 'Reading Excel…';
        try {
            if (!window.XLSX) await grLoadScript('https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js');
            const buf  = await file.arrayBuffer();
            const wb   = XLSX.read(buf, { type:'array' });
            const ws   = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, { header:1, defval:'' });
            const result = grParseNamesText(rows.map(r => r.join('\t')).join('\n'));
            if (!result.length) { statusEl.textContent = 'No names found in Excel.'; return; }
            statusEl.textContent = '✅ Found ' + result.length + ' students';
            onDone(result);
        } catch(e) { statusEl.textContent = '❌ ' + e.message; }
        return;
    }
    // Image/PDF → Gemini
    if (!GR_GEMINI_KEY) {
        GR_GEMINI_KEY = prompt('Image/PDF roster scanning needs a Gemini API key. Enter it now, or cancel and use Paste / CSV / Excel instead:');
        if (GR_GEMINI_KEY) { GM_setValue('geminiKey', GR_GEMINI_KEY); GEMINI_API_KEY_STC = GR_GEMINI_KEY; }
        else { statusEl.textContent = 'Skipped: no API key. Use paste / CSV / Excel instead.'; return; }
    }
    statusEl.textContent = '⏳ Reading document…';
    try {
        let base64data, mediaType;
        if (ext === 'pdf') {
            base64data = grArrayBufToB64(await file.arrayBuffer()); mediaType = 'application/pdf';
        } else if (['heic','heif'].includes(ext)) {
            base64data = grArrayBufToB64(await file.arrayBuffer()); mediaType = 'image/heic';
        } else {
            const r = await new Promise((resolve, reject) => {
                const url = URL.createObjectURL(file);
                const img = new Image();
                img.onload = () => {
                    const MAX = 1568; let w = img.naturalWidth, h = img.naturalHeight;
                    if (w > MAX || h > MAX) { if (w>=h){h=Math.round(h*MAX/w);w=MAX;}else{w=Math.round(w*MAX/h);h=MAX;} }
                    const c = document.createElement('canvas'); c.width=w; c.height=h;
                    c.getContext('2d').drawImage(img,0,0,w,h);
                    URL.revokeObjectURL(url);
                    resolve({ base64: c.toDataURL('image/jpeg',0.85).split(',')[1], type:'image/jpeg' });
                };
                img.onerror = () => { URL.revokeObjectURL(url); reject(new Error('Could not decode image')); };
                img.src = url;
            });
            base64data = r.base64; mediaType = r.type;
        }
        const result = await grCallGemini(base64data, mediaType);
        statusEl.textContent = '✅ Found ' + result.length + ' students';
        onDone(result);
    } catch(e) { statusEl.textContent = '❌ ' + e.message; }
}



async function grBuildPdf(ci, students) {
    const { PDFDocument, rgb, StandardFonts, degrees } = PDFLib;

    const pdfDoc = await PDFDocument.create();
    const font     = await pdfDoc.embedFont(StandardFonts.Helvetica);
    const fontBold = await pdfDoc.embedFont(StandardFonts.HelveticaBold);

    // Embed logo
    const logoBytes = Uint8Array.from(atob(GR_LOGO_B64), c => c.charCodeAt(0));
    const logoImg   = await pdfDoc.embedPng(logoBytes);

    // Page: landscape letter 792 x 612
    const PW = 792, PH = 612;

    // Column X positions
    const COLS = [36.0, 62.9, 274.3, 530.9, 764.9];
    const COL_W = [COLS[1]-COLS[0], COLS[2]-COLS[1], COLS[3]-COLS[2], COLS[4]-COLS[3]];

    // Row heights
    const HDR_H  = 15.1;   // header row
    const ROW_H  = 46.8;   // data row

    // Page 1: 6 data rows, starts at y_top=199.0
    // Page 2+: 10 data rows, starts at y_top=63.5
    const P1_TABLE_TOP  = 199.0;  // from top of page
    const P2_TABLE_TOP  = 63.5;
    const P1_ROWS = 6;
    const P2_ROWS = 10;

    // Calculate pages needed
    const totalPages = Math.max(1, Math.ceil(students.length / P1_ROWS) === 0 ? 1 :
        students.length <= P1_ROWS ? 1 : 1 + Math.ceil((students.length - P1_ROWS) / P2_ROWS));
    // Simpler:
    const pageCount = students.length <= P1_ROWS ? 1
        : 1 + Math.ceil((students.length - P1_ROWS) / P2_ROWS);

    // ── helpers ──────────────────────────────────────────────────────────────

    // pdf-lib Y: 0=bottom, PH=top. Input y_top = distance from top of page.
    const Y = (y_top) => PH - y_top;

    function drawRect(page, x, y_top, w, h, opts={}) {
        page.drawRectangle({
            x, y: Y(y_top + h), width: w, height: h,
            borderColor: opts.borderColor || rgb(0,0,0),
            borderWidth:  opts.borderWidth !== undefined ? opts.borderWidth : 0.5,
            color:        opts.color || undefined,
        });
    }

    function drawLine(page, x1, x2, y_top, opts={}) {
        page.drawLine({
            start: {x: x1, y: Y(y_top)},
            end:   {x: x2, y: Y(y_top)},
            thickness: opts.thickness || 0.5,
            color: opts.color || rgb(0,0,0),
        });
    }

    function txt(page, text, x, y_top, opts={}) {
        if (!text) return;
        page.drawText(text, {
            x, y: Y(y_top + (opts.size || 12) * 0.75),  // baseline approx
            size:  opts.size  || 12,
            font:  opts.bold  ? fontBold : font,
            color: opts.color || rgb(0,0,0),
            maxWidth: opts.maxWidth,
        });
    }

    function txtCenter(page, text, x1, x2, y_top, opts={}) {
        const sz   = opts.size || 12;
        const tw   = (opts.bold ? fontBold : font).widthOfTextAtSize(text, sz);
        const cx   = x1 + (x2 - x1 - tw) / 2;
        txt(page, text, cx, y_top, opts);
    }

    // Shrink-to-fit + truncate. Tries sizes [maxSize, maxSize-1, ...minSize].
    // If still doesn't fit at minSize, truncates with an ellipsis.
    // Single-line: no wrap, ever.
    function txtFit(page, text, x, y_top, maxWidth, opts={}) {
        if (!text) return;
        const maxSize = opts.maxSize || 12;
        const minSize = opts.minSize || 9;
        const f = opts.bold ? fontBold : font;
        for (let s = maxSize; s >= minSize; s--) {
            if (f.widthOfTextAtSize(text, s) <= maxWidth) {
                txt(page, text, x, y_top, { ...opts, size: s });
                return;
            }
        }
        // Doesn't fit even at minSize — truncate with ellipsis
        let t = text;
        while (t.length > 1 && f.widthOfTextAtSize(t + '\u2026', minSize) > maxWidth) {
            t = t.slice(0, -1);
        }
        txt(page, t + '\u2026', x, y_top, { ...opts, size: minSize });
    }

    // ── draw table on a page ─────────────────────────────────────────────────
    function drawTable(page, startStudent, rowCount, tableTopY) {
        // Outer border
        const tableH = HDR_H + rowCount * ROW_H;
        drawRect(page, COLS[0], tableTopY, COLS[4]-COLS[0], tableH, {borderWidth:0.5});

        // Header row bottom line
        drawLine(page, COLS[0], COLS[4], tableTopY + HDR_H);

        // Vertical dividers (full height)
        drawLine(page, COLS[1], COLS[1], tableTopY,     {thickness:0.5});  // only needed inside
        drawLine(page, COLS[2], COLS[2], tableTopY,     {thickness:0.5});
        drawLine(page, COLS[3], COLS[3], tableTopY,     {thickness:0.5});
        // But pdf-lib drawLine is from start y to end y differently — draw full column lines
        page.drawLine({ start:{x:COLS[1], y:Y(tableTopY+tableH)}, end:{x:COLS[1], y:Y(tableTopY)}, thickness:0.5, color:rgb(0,0,0) });
        page.drawLine({ start:{x:COLS[2], y:Y(tableTopY+tableH)}, end:{x:COLS[2], y:Y(tableTopY)}, thickness:0.5, color:rgb(0,0,0) });
        page.drawLine({ start:{x:COLS[3], y:Y(tableTopY+tableH)}, end:{x:COLS[3], y:Y(tableTopY)}, thickness:0.5, color:rgb(0,0,0) });

        // Header text (centered in each col)
        const hy = tableTopY + 2;
        txtCenter(page, 'Student Name / Phone Number', COLS[1], COLS[2], hy, {size:11});
        txtCenter(page, 'Address',                     COLS[2], COLS[3], hy, {size:11});
        txtCenter(page, 'Work Email Address / Personal Email Address', COLS[3], COLS[4], hy, {size:10});

        // Data rows
        for (let r = 0; r < rowCount; r++) {
            const rowTopY = tableTopY + HDR_H + r * ROW_H;
            // Bottom border of each row
            if (r < rowCount - 1) {
                drawLine(page, COLS[0], COLS[4], rowTopY + ROW_H);
            }
            // Row number
            const num = startStudent + r;
            const numStr = String(num);
            const sz = 12;
            const tw = font.widthOfTextAtSize(numStr, sz);
            txt(page, numStr, COLS[0] + (COL_W[0] - tw)/2, rowTopY + 3, {size:sz});

            // Student name + email if we have data
            const s = students[num - 1];
            if (s) {
                const maxNameW = COL_W[1] - 6;
                txt(page, s.name || '', COLS[1] + 3, rowTopY + 3, {size:10, maxWidth: maxNameW});
                const maxEmailW = COL_W[3] - 6;
                txt(page, s.email || '', COLS[3] + 3, rowTopY + 3, {size:10, maxWidth: maxEmailW});
            }
        }
    }

    // ── draw footer ──────────────────────────────────────────────────────────
    function drawFooter(page, pgNum, pgTotal) {
        // "Visit us on the web at –" at x=144, y_top=519.9 (page 1) / y_top=546.6 (page 2+)
        const fy = page === pages[0] ? 519.9 : 546.6;
        txt(page, 'Visit us on the web at \u2013 ', 144, fy, {size:12});
        // URL in blue
        txt(page, 'www.SafetyUnlimited.com', 260.3, fy, {size:12, color:rgb(0.019,0.388,0.757)});
        // Blue underline
        drawLine(page, 260.3, 390.2, fy + 13.5, {thickness:0.5, color:rgb(0.019,0.388,0.757)});
        // Page X of Y
        txt(page, 'Page ', 504, fy, {size:10});
        const pnumW = font.widthOfTextAtSize(String(pgNum), 10);
        // underlined page number
        txt(page, String(pgNum), 540, fy, {size:10});
        drawLine(page, 528, 555, fy + 11.5, {thickness:0.5});
        txt(page, ' of ', 555, fy, {size:10});
        txt(page, String(pgTotal), 612, fy, {size:10});
        drawLine(page, 600, 627, fy + 11.5, {thickness:0.5});
    }

    // ── build pages ──────────────────────────────────────────────────────────
    const pages = [];

    for (let pg = 1; pg <= pageCount; pg++) {
        const page = pdfDoc.addPage([PW, PH]);
        pages.push(page);
        const isFirst = pg === 1;
        const rowsOnPage = isFirst ? P1_ROWS : P2_ROWS;
        const tableTopY  = isFirst ? P1_TABLE_TOP : P2_TABLE_TOP;
        const startNum   = isFirst ? 1 : P1_ROWS + (pg-2)*P2_ROWS + 1;

        if (isFirst) {
            // ── Logo (top-left) ──────────────────────────────────────────
            page.drawImage(logoImg, { x:36, y:Y(86.7), width:137.2, height:50.7 });

            // ── Yellow title box ─────────────────────────────────────────
            page.drawRectangle({ x:268, y:Y(72), width:229.6, height:51.2, color:rgb(1,1,0) });
            // Title text (bold, centered in box)
            txtCenter(page, 'Class Roster',          268, 497.6, 24.6 + 2,  {size:18, bold:true});
            txtCenter(page, '(Please Print Clearly)', 268, 497.6, 46.7 + 2, {size:18, bold:true});

            // ── Address box (top-right) ───────────────────────────────────
            page.drawRectangle({ x:617.6, y:Y(78.4), width:148.8, height:52, borderColor:rgb(0,0,0), borderWidth:0.5, color:rgb(1,1,1) });
            txt(page, '2139 Tapo Street  Suite 228', 625.2, 30.3 + 2, {size:11});
            txt(page, 'Simi Valley, CA 93063',       640.3, 45.0 + 2, {size:11});
            txt(page, '888-309-7233 (SAFE)',          641.0, 59.9 + 2, {size:11});

            // ── Class info line ───────────────────────────────────────────
            // Class line: title capped to underline width, instructor + date aligned
            txt(page, 'Class:', 36, 116, {size:12});
            // Class title: single-line auto-shrink + ellipsis (never wraps).
            // Start at x=72 so "Class:" label (~32 units wide at size 12) doesn't overlap.
            txtFit(page, ci.courseTitle || '', 72, 116, 212, {maxSize:12, minSize:9});
            drawLine(page, 72, 288.0, 129.6);
            txt(page, 'Instructor:', 288, 116, {size:12});
            // Instructor: same treatment so long names don't wrap either
            txtFit(page, ci.instructor || '', 356, 116, 212, {maxSize:12, minSize:9});
            txt(page, 'Date(s)', 576, 116, {size:12});
            txtFit(page, ci.startDate || '', 626, 116, 94, {maxSize:12, minSize:9});
            drawLine(page, 624.5, 721.9, 129.6);

            // ── Customer: ____  Location: <addr>  Hours: ____ (one clean line)
            txt(page, 'Customer:', 36, 145.3, {size:12});
            txtFit(page, ci.customer || '', 96, 145.3, 152, {maxSize:12, minSize:6});
            drawLine(page, 96, 256.6, 158.9);
            txt(page, 'Location:', 270, 145.3, {size:12});
            txtFit(page, ci.location || '', 324, 145.3, 254, {maxSize:12, minSize:6});
            txt(page, 'Hours:', 590, 145.3, {size:12});
            txtFit(page, ci.hours || '', 630, 145.3, 88, {maxSize:12, minSize:9});
            drawLine(page, 628, 720.0, 158.9);

            // ── Confidential notice ───────────────────────────────────────
            const confText = 'ALL INFORMATION ENTERED HERE IS KEPT CONFIDENTIAL AND IS ONLY FOR YOUR STUDENT ACCESS TO YOUR ONLINE ACCOUNT';
            const confW = fontBold.widthOfTextAtSize(confText, 10);
            const confX = (PW - confW) / 2;
            txt(page, confText, confX, 174.5, {size:10, bold:true});
            drawLine(page, confX, confX + confW, 186.8);  // underline

        } else {
            // ── Pages 2+: just class/instructor/date header ───────────────
            txt(page, 'Class: ' + (ci.courseTitle || ''), 36, 36.1, {size:12});
            txt(page, 'Instructor: ' + (ci.instructor || ''), 396, 36.1, {size:12});
            txt(page, 'Date(s) ' + (ci.startDate || ''), 576, 36.1, {size:12});
        }

        // ── Table ─────────────────────────────────────────────────────────
        drawTable(page, startNum, rowsOnPage, tableTopY);

        // ── Footer ────────────────────────────────────────────────────────
        drawFooter(page, pg, pageCount);
    }

    const pdfBytes = await pdfDoc.save();
    return new Blob([pdfBytes], { type: 'application/pdf' });
}


